class Solution {
public:
    ListNode* reverseList(ListNode* head) {
        ListNode* prev = nullptr;
        ListNode* curr = head;
        while (curr) {
            ListNode* next = curr->next; // 先暂存后继，防止改指针后断链
            curr->next = prev; // 掉头：不变量是 prev 之前的部分已完成反转
            prev = curr;
            curr = next;
        }
        return prev;
    }
};
